#include <iostream>
#include <iomanip>

struct Temperature {
    double celsius{};

    Temperature(double c) : celsius{c} {
        std::cout << std::fixed << std::setprecision(1)
                  << "Constructed: " << celsius << "C\n";
    }

    Temperature(const Temperature& src) : celsius{src.celsius} {
        std::cout << std::fixed << std::setprecision(1)
                  << "Copy constructor: " << celsius << "C\n";
    }
};

void printByValue(Temperature t) {
    std::cout << std::fixed << std::setprecision(1)
              << "Passed by value: " << t.celsius << "C\n";
}

Temperature makeTemperature(double c) {
    Temperature local{c};
    return local;
}

int main() {
    double val{};
    std::cin >> val;

    Temperature a{val};
    Temperature b = a;
    printByValue(b);
    Temperature ret = makeTemperature(val);
    std::cout << std::fixed << std::setprecision(1)
              << "Returned by value: " << ret.celsius << "C\n";

    return 0;
}

