#include <iostream>
#include <iomanip>
#include <string>

struct Student {
private:
    std::string m_name;
    int m_grades[5]{};
    int m_count{};

public:
    Student(const std::string& name, const int* g, int n)
        : m_name{name}, m_count{n} {
        for (int i = 0; i < m_count; ++i)
            m_grades[i] = g[i];
    }

    Student(const Student& src)
        : m_name{src.m_name}, m_count{src.m_count} {
        std::cout << "Copy constructor called for: " << src.m_name << '\n';
        for (int i = 0; i < m_count; ++i)
            m_grades[i] = src.m_grades[i];
    }

    double average() const {
        double sum = 0;
        for (int i = 0; i < m_count; ++i)
            sum += m_grades[i];
        return sum / m_count;
    }

    const std::string& getName() const { return m_name; }

    int getGrade(int i) const { return m_grades[i]; }

    int getCount() const { return m_count; }

    void rename(const std::string& newName) { m_name = newName; }
};

int main() {
    std::string name;
    int n;
    std::cin >> name >> n;

    int g[5]{};
    for (int i = 0; i < n; ++i)
        std::cin >> g[i];

    Student original{name, g, n};
    Student copy = original;
    copy.rename("Clone");

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Original: " << original.getName() << " avg=" << original.average() << '\n';
    std::cout << "Copy: " << copy.getName() << " avg=" << copy.average() << '\n';
    std::cout << "After rename, original: " << original.getName() << " avg=" << original.average() << '\n';
    std::cout << "After rename, copy: " << copy.getName() << " avg=" << copy.average() << '\n';

    bool match = true;
    for (int i = 0; i < original.getCount(); ++i)
        if (original.getGrade(i) != copy.getGrade(i)) { match = false; break; }
    std::cout << "Grades match: " << (match ? "yes" : "no") << '\n';

    return 0;
}
